  ('promotion-6f0ba476-moex-00004', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司宣告並發放 X2 年股利$450,000 予普通股股東與特別股股東。甲公司有 100,000 股普 通股流通在外，每股面額$10，及50,000股10%特別股流通在外，每股面額$16。若特別股為 累積且可參加至14%，並積欠股利1年，則特別股與普通股每股可領取之金額分別為多少？', '["特別股$2.24、普通股$3.38", "特別股$3.00、普通股$3.00", "特別股$3.84、普通股$2.58", "特別股$4.00、普通股$2.50"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL)
